## Phase 2: SEO Layer Updates

### Overview
Remove `ogImage` references from metadata builders and JSON-LD builders. For metadata, the colocated `opengraph-image.tsx` route handlers (existing + new ones in Phase 3) set `og:image` automatically. For JSON-LD, use the canonical URL to construct the OG image path.

### Changes Required:

#### 1. SEO Bundle — Article Metadata

**File**: `apps/www/src/lib/seo-bundle.ts`

**Remove `openGraph.images` and `twitter.images` from `buildArticleMetadata`** (lines 69-71, 80):

The `openGraph` object should no longer include `images`, and `twitter` should no longer include `images`. The colocated `opengraph-image.tsx` route handler automatically sets the `<meta og:image>` tag, overriding any value set here.

```typescript
function buildArticleMetadata(
  data: ContentSeoData,
  canonicalUrl: string,
  titleSuffix: string,
  siteName: string
): Metadata {
  return createArticleMetadata(
    {
      title: `${data.title} – ${titleSuffix}`,
      description: data.description,
      keywords: data.keywords,
      authors: data.authors.map((a) => ({ name: a.name, url: a.url })),
      creator: "Lightfast",
      publisher: "Lightfast",
      robots: {
        index: !data.noindex,
        follow: !data.nofollow,
        googleBot: {
          index: !data.noindex,
          follow: !data.nofollow,
          "max-video-preview": -1,
          "max-image-preview": "large",
          "max-snippet": -1,
        },
      },
      alternates: { canonical: canonicalUrl },
      openGraph: {
        title: data.ogTitle,
        description: data.ogDescription,
        url: canonicalUrl,
        siteName,
        locale: "en_US",
        authors: data.authors.map((a) => a.url),
      },
      twitter: {
        card: "summary_large_image",
        title: data.ogTitle,
        description: data.ogDescription,
        site: "@lightfastai",
        creator: "@lightfastai",
      },
      category: "Technology",
    },
    { publishedAt: data.publishedAt, updatedAt: data.updatedAt }
  );
}
```

#### 2. SEO Bundle — Legal Metadata

**File**: `apps/www/src/lib/seo-bundle.ts`

**Remove `openGraph.images` and `twitter.images` from `emitLegalSeo`** (lines 165-167, 175):

```typescript
export function emitLegalSeo(data: LegalPageData, url: LegalUrl): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: createMetadata({
      title: `${data.title} – Lightfast`,
      description: data.description,
      keywords: data.keywords,
      creator: "Lightfast",
      publisher: "Lightfast",
      robots: {
        index: !data.noindex,
        follow: !data.nofollow,
        googleBot: {
          index: !data.noindex,
          follow: !data.nofollow,
          "max-video-preview": -1,
          "max-image-preview": "large",
          "max-snippet": -1,
        },
      },
      alternates: { canonical: canonicalUrl },
      openGraph: {
        title: data.ogTitle,
        description: data.ogDescription,
        type: "website",
        url: canonicalUrl,
        siteName: "Lightfast",
        locale: "en_US",
      },
      twitter: {
        card: "summary_large_image",
        title: data.ogTitle,
        description: data.ogDescription,
        site: "@lightfastai",
        creator: "@lightfastai",
      },
    }),
    jsonLd: buildLegalJsonLd(data, url),
  };
}
```

#### 3. Blog JSON-LD Builder

**File**: `apps/www/src/lib/builders/blog.ts`

**Replace `data.ogImage` with URL-derived OG image path** (lines 36-41):

The `url` parameter is already passed to `buildBlogPostJsonLd`. Thread it through to `buildBlogPostEntity`:

```typescript
function buildBlogPostEntity(
  data: BlogPostData,
  url: BlogPostUrl
): Omit<BlogPosting, "@id" | "url"> {
  return {
    "@type": "BlogPosting",
    headline: data.title,
    description: data.description,
    abstract: data.tldr,
    datePublished: data.publishedAt,
    dateModified: data.updatedAt,
    author: data.authors.map((a) => ({
      "@type": "Person" as const,
      name: a.name,
      url: a.url,
      sameAs: [`https://x.com/${a.twitterHandle.replace(/^@/, "")}`],
    })),
    image: {
      "@type": "ImageObject" as const,
      url: `${url}/opengraph-image`,
      width: "1200",
      height: "630",
    },
    keywords: data.keywords.join(", "),
    articleSection: ARTICLE_SECTIONS[data.category],
    inLanguage: "en-US",
    isPartOf: { "@id": "https://lightfast.ai/#website" },
    publisher: { "@id": "https://lightfast.ai/#organization" },
  };
}

export function buildBlogPostJsonLd(
  data: BlogPostData,
  url: BlogPostUrl
): GraphContext {
  const entity = buildBlogPostEntity(data, url);
  // ... rest unchanged
}
```

