## Phase 3: Add Missing OG Route Handlers

### Overview
Create `opengraph-image.tsx` route handlers for legal, docs, and API reference pages. This ensures all content types have programmatic OG image generation, making the removed `ogImage` frontmatter fully redundant.

### Changes Required:

#### 1. Legal OG Handler

**File**: `apps/www/src/app/(app)/(marketing)/legal/[slug]/opengraph-image.tsx` (new file)

Uses `FeatureLayout` — appropriate for legal pages (simple title + description, no author/date).

```tsx
import { FeatureLayout } from "@repo/og";
import { OG_HEIGHT, OG_WIDTH } from "@repo/og/brand";
import { ImageResponse } from "next/og";
import { getLegalPage } from "~/app/(app)/(content)/_lib/source";
import { loadOGFonts } from "~/lib/og-fonts";

export const runtime = "nodejs";
export const alt = "Lightfast Legal";
export const size = { width: OG_WIDTH, height: OG_HEIGHT };
export const contentType = "image/png";

export default async function Image({
  params,
}: {
  params: Promise<{ slug: string }>;
}) {
  const { slug } = await params;
  const page = getLegalPage([slug]);
  const fonts = await loadOGFonts();

  if (!page) {
    return new ImageResponse(<div>Not Found</div>, { ...size });
  }

  const { title, description } = page.data;

  return new ImageResponse(
    <FeatureLayout description={description} title={title} />,
    { ...size, fonts }
  );
}
```

#### 2. Docs OG Handler

**File**: `apps/www/src/app/(app)/(content)/docs/(general)/[[...slug]]/opengraph-image.tsx` (new file)

Uses `DocsLayout` with breadcrumb segments from the slug.

```tsx
import { DocsLayout } from "@repo/og";
import { OG_HEIGHT, OG_WIDTH } from "@repo/og/brand";
import { ImageResponse } from "next/og";
import { getPage } from "~/app/(app)/(content)/_lib/source";
import { loadOGFonts } from "~/lib/og-fonts";

export const runtime = "nodejs";
export const alt = "Lightfast Documentation";
export const size = { width: OG_WIDTH, height: OG_HEIGHT };
export const contentType = "image/png";

function toTitleCase(segment: string): string {
  return segment
    .split("-")
    .map((s) => (s[0]?.toUpperCase() ?? "") + s.slice(1))
    .join(" ");
}

export default async function Image({
  params,
}: {
  params: Promise<{ slug?: string[] }>;
}) {
  const { slug } = await params;
  const fonts = await loadOGFonts();

  if (!slug || slug.length === 0) {
    return new ImageResponse(
      <DocsLayout title="Documentation" />,
      { ...size, fonts }
    );
  }

  const page = getPage(slug);

  if (!page) {
    return new ImageResponse(<div>Not Found</div>, { ...size });
  }

  const { title } = page.data;

  return new ImageResponse(
    <DocsLayout
      breadcrumb={slug.map(toTitleCase)}
      title={title}
    />,
    { ...size, fonts }
  );
}
```

#### 3. API Reference OG Handler

**File**: `apps/www/src/app/(app)/(content)/docs/(api)/api-reference/[[...slug]]/opengraph-image.tsx` (new file)

Uses `DocsLayout` with section "API Reference".

```tsx
import { DocsLayout } from "@repo/og";
import { OG_HEIGHT, OG_WIDTH } from "@repo/og/brand";
import { ImageResponse } from "next/og";
import { getApiPage } from "~/app/(app)/(content)/_lib/source";
import { loadOGFonts } from "~/lib/og-fonts";

export const runtime = "nodejs";
export const alt = "Lightfast API Reference";
export const size = { width: OG_WIDTH, height: OG_HEIGHT };
export const contentType = "image/png";

export default async function Image({
  params,
}: {
  params: Promise<{ slug?: string[] }>;
}) {
  const { slug } = await params;
  const fonts = await loadOGFonts();

  if (!slug || slug.length === 0) {
    return new ImageResponse(
      <DocsLayout section="API Reference" title="API Reference" />,
      { ...size, fonts }
    );
  }

  const page = getApiPage(slug);

  if (!page) {
    return new ImageResponse(<div>Not Found</div>, { ...size });
  }

  const title = page.data.title ?? "API Reference";

  return new ImageResponse(
    <DocsLayout section="API Reference" title={title} />,
    { ...size, fonts }
  );
}
```

